<?php if (isset($_GET['gclid'])) { $_SESSION['sessao_ads'] = true; } $varTipoSess = isset($_SESSION['sessao_ads']) ? $_SESSION['sessao_ads'] : false; ?> <script> $('[data-click-track]').click(function(){ event.preventDefault(); var buscaorganicaUrlContactTrack = 'https://www.buscaorganica.com.br/includes/buscaorganica/clicktracker.php'; var hrefCT = $(this).attr('href');var nomeCT = $(this).data('click-track');var ipCT = '<?php echo $_SERVER['REMOTE_ADDR'];?>';var urlCT = '<?php echo $url;?>';var canonicalCT = '<?php echo str_replace($url, '', $canonical);?>';var titleCT = '<?php echo $title;?>';var tipoCT = '<?php echo isset($varTipoSess) && $varTipoSess == true ? "ads" : "organic" ;?>'; $.ajax({ type: 'POST', data: {acao: 'click-tracker', href: hrefCT, nome: nomeCT, ip: ipCT, url: urlCT, canonical: canonicalCT, title: titleCT, tipo: tipoCT}, url: buscaorganicaUrlContactTrack }).done(function(xhrRet){ console.log('retorno',xhrRet); window.location.href = hrefCT;});});</script>